function Decrypt-ChromePass([byte[]]$key,[byte[]]$blob){
  if($blob.Length -lt 15){ return $null }
  # v10/v11 AES-GCM: 'v10' + 12 nonce + ciphertext+tag
  $prefix=[Text.Encoding]::ASCII.GetString($blob[0..2])
  if($prefix -ne 'v10' -and $prefix -ne 'v11'){
    # old DPAPI
    try{ return [Text.Encoding]::UTF8.GetString([Security.Cryptography.ProtectedData]::Unprotect($blob,$null,'CurrentUser')) } catch { return $null }
  }
  $nonce=$blob[3..14]
  $cipherTag=$blob[15..($blob.Length-1)]
  $tag=$cipherTag[($cipherTag.Length-16)..($cipherTag.Length-1)]
  $cipher=$cipherTag[0..($cipherTag.Length-17)]
  # use BouncyCastle or .NET AesGcm if available
  try {
    $aes=[Security.Cryptography.AesGcm]::new($key)
    $plain=New-Object byte[] $cipher.Length
    $aes.Decrypt($nonce,$cipher,$tag,$plain)
    return [Text.Encoding]::UTF8.GetString($plain)
  } catch {
    return "AESGCM_FAIL:$($_.Exception.Message)"
  }
}
