import os, json, sqlite3, shutil, base64, tempfile, sys

def get_key(local_state):
    with open(local_state, "r", encoding="utf-8") as f:
        d = json.load(f)
    enc = base64.b64decode(d["os_crypt"]["encrypted_key"])[5:]
    import ctypes
    from ctypes import wintypes

    class DATA_BLOB(ctypes.Structure):
        _fields_ = [("cbData", wintypes.DWORD), ("pbData", ctypes.POINTER(ctypes.c_char))]

    blob_in = DATA_BLOB(len(enc), ctypes.create_string_buffer(enc, len(enc)))
    blob_out = DATA_BLOB()
    if not ctypes.windll.crypt32.CryptUnprotectData(
        ctypes.byref(blob_in), None, None, None, None, 0, ctypes.byref(blob_out)
    ):
        raise OSError("CryptUnprotectData failed")
    data = ctypes.string_at(blob_out.pbData, blob_out.cbData)
    ctypes.windll.kernel32.LocalFree(blob_out.pbData)
    return data


def decrypt(buf, key):
    if buf[:3] in (b"v10", b"v20"):
        try:
            from Cryptodome.Cipher import AES
        except ImportError:
            from Crypto.Cipher import AES
        iv, payload = buf[3:15], buf[15:]
        cipher = AES.new(key, AES.MODE_GCM, iv)
        return cipher.decrypt(payload)[:-16].decode("utf-8", "replace")
    import ctypes
    from ctypes import wintypes

    class DATA_BLOB(ctypes.Structure):
        _fields_ = [("cbData", wintypes.DWORD), ("pbData", ctypes.POINTER(ctypes.c_char))]

    blob_in = DATA_BLOB(len(buf), ctypes.create_string_buffer(buf, len(buf)))
    blob_out = DATA_BLOB()
    if not ctypes.windll.crypt32.CryptUnprotectData(
        ctypes.byref(blob_in), None, None, None, None, 0, ctypes.byref(blob_out)
    ):
        return "DPAPI_FAIL"
    data = ctypes.string_at(blob_out.pbData, blob_out.cbData)
    ctypes.windll.kernel32.LocalFree(blob_out.pbData)
    return data.decode("utf-8", "replace")


NEED = ("fastvps", "vps.ru", "sb37", "46.36.221", "mtproto", "mtproxy", "telegram")
roots = [
    ("Edge", os.path.expandvars(r"%LOCALAPPDATA%\Microsoft\Edge\User Data")),
    ("Chrome", os.path.expandvars(r"%LOCALAPPDATA%\Google\Chrome\User Data")),
    ("Yandex", os.path.expandvars(r"%LOCALAPPDATA%\Yandex\YandexBrowser\User Data")),
]
for name, root in roots:
    ls = os.path.join(root, "Local State")
    if not os.path.exists(ls):
        print(name, "NO_LS")
        continue
    try:
        key = get_key(ls)
    except Exception as e:
        print(name, "KEY_FAIL", e)
        continue
    for dirpath, _, files in os.walk(root):
        if "Login Data" not in files or "Network" in dirpath:
            continue
        src = os.path.join(dirpath, "Login Data")
        tmp = tempfile.mktemp(suffix=".db")
        shutil.copy2(src, tmp)
        try:
            con = sqlite3.connect(tmp)
            for origin, user, pwd in con.execute(
                "select origin_url, username_value, password_value from logins"
            ):
                blob = f"{origin} {user or ''}".lower()
                if any(n in blob for n in NEED):
                    try:
                        pw = decrypt(pwd, key) if pwd else ""
                    except Exception as e:
                        pw = f"DEC_FAIL:{e}"
                    print(f"{name}|{origin}|{user}|{pw}")
            # also dump all origins containing vps
            for (origin,) in con.execute("select distinct origin_url from logins"):
                if "vps" in (origin or "").lower() or "hosting" in (origin or "").lower():
                    print(f"ORIGIN|{name}|{origin}")
            con.close()
        except Exception as e:
            print(name, "DB_FAIL", e)
        finally:
            try:
                os.remove(tmp)
            except OSError:
                pass
print("DONE")

