        shutil.copy2(src, tmp)
        try:
            con = sqlite3.connect(tmp)
            rows = list(con.execute("select origin_url, username_value, password_value from logins"))
            print(name, dirpath, "logins", len(rows))
            for origin, user, pwd in rows:
                blob = f"{origin} {user or ''}".lower()
                if any(n in blob for n in NEED) or True:  # dump ALL then filter later for small dbs
                    if len(rows) > 30 and not any(n in blob for n in NEED):
