def row_dict(r: sqlite3.Row) -> dict[str, Any]:
    return dict(r)


def fetch_checkmk_states() -> dict[str, str]:
    """host -> state: UP/DOWN/UNREACH/unknown"""
    states: dict[str, str] = {}
    try:
        # Prefer REST API with basic auth (works out of the box for cmkadmin)
        url = f"{CMK_URL}/check_mk/api/1.0/domain-types/host/collections/all"
        with httpx.Client(timeout=4.0, follow_redirects=True) as client:
            r = client.get(
                url,
                auth=(CMK_USER, CMK_PASS),
                headers={"Accept": "application/json"},
            )
            if r.status_code == 200:
                data = r.json()
                for h in data.get("value", []):
                    ext = h.get("extensions", {})
                    name = ext.get("name") or h.get("id")
                    # live status often needs separate query; mark present hosts as monitored
                    if name:
                        states[name] = "MONITORED"
            # host problems
            r2 = client.get(
