def row_dict(r: sqlite3.Row) -> dict[str, Any]:
    return dict(r)


STATE_MAP = {0: "UP", 1: "DOWN", 2: "UNREACH", "0": "UP", "1": "DOWN", "2": "UNREACH"}


def fetch_checkmk_states() -> dict[str, dict[str, Any]]:
    """host_name -> {status, plugin_output, state_code}"""
    out: dict[str, dict[str, Any]] = {}
    try:
        with httpx.Client(timeout=5.0, follow_redirects=True) as client:
            r = client.get(
                f"{CMK_URL}/check_mk/api/1.0/domain-types/host/collections/all",
                auth=(CMK_USER, CMK_PASS),
                headers={"Accept": "application/json"},
            )
            if r.status_code != 200:
                return out
            for h in r.json().get("value", []):
                ext = h.get("extensions", {}) or {}
                name = ext.get("name") or h.get("id") or ""
                # try several shapes of API payload
                st = ext.get("state")
                if st is None and isinstance(ext.get("attributes"), dict):
                    st = ext["attributes"].get("state")
                # livestatus sometimes nested
                for key in ("state", "hard_state"):
                    if st is None and key in ext:
                        st = ext[key]
                status = STATE_MAP.get(st, "UNKNOWN" if st is None else str(st))
                # If present in monitoring collection without state field, treat as UP-ish monitored
                if status == "UNKNOWN" and name:
                    status = "UP"
                out[name] = {
                    "status": status,
                    "output": ext.get("plugin_output") or ext.get("summary") or "",
                    "state_code": st,
                }
    except Exception:
        pass
    return out


