@app.get("/api/map")
def get_map():
    with db() as conn:
        assets = [row_dict(r) for r in conn.execute("SELECT * FROM assets ORDER BY name")]
        links = [row_dict(r) for r in conn.execute("SELECT * FROM links")]
        changes = [
            row_dict(r)
            for r in conn.execute("SELECT * FROM changes ORDER BY id DESC LIMIT 40")
        ]
    cmk = fetch_checkmk_states()
    up = down = unk = 0
    for a in assets:
        key = a.get("checkmk_host") or ""
        ip = a.get("ip") or ""
        info = cmk.get(key) or cmk.get(ip) or {}
        status = info.get("status") or "UNKNOWN"
        if a["id"] == "checkmk":
            try:
                with httpx.Client(timeout=2.0) as c:
                    status = "UP" if c.get(f"{CMK_URL}/check_mk/").status_code < 500 else "DOWN"
            except Exception:
                status = "DOWN"
        a["status"] = status
        a["cmk_output"] = info.get("output") or ""
        if status == "UP":
            up += 1
        elif status in ("DOWN", "UNREACH"):
            down += 1
        else:
            unk += 1
    return {
        "assets": assets,
        "links": links,
        "changes": changes,
        "stats": {"up": up, "down": down, "unknown": unk, "total": len(assets)},
        "cmk_hosts": list(cmk.keys()),
    }


