        <div>
          <label>Узел</label>
          <select id="asset_id"></select>
        </div>
        <div>
          <label>Что изменилось</label>
          <input id="title" placeholder="Напр. Сменилась база трубки 213" required/>
        </div>
        <div>
          <label>Детали</label>
          <textarea id="detail" rows="2" placeholder="Было → стало, кто, зачем"></textarea>
        </div>
        <div class="row">
          <div>
            <label>Автор</label>
            <input id="author" value="it"/>
          </div>
          <div style="display:flex;align-items:end">
