<script>
let DATA = {assets:[], links:[], changes:[], stats:{}};
let drag = null;

function showTab(name){
  document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active', b.dataset.tab===name));
  document.getElementById('panel-changes').style.display = name==='changes' ? 'block' : 'none';
  document.getElementById('panel-assets').style.display = name==='assets' ? 'block' : 'none';
}

async function loadMap(){
  const r = await fetch('/api/map');
  DATA = await r.json();
  render();
}

function esc(s){
  return String(s??'').replace(/[&<>"']/g, m=>({ '&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;' }[m]));
}

function render(){
  const svg = document.getElementById('map');
  const W = Math.max(svg.clientWidth || 900, 900);
  const H = Math.max(svg.clientHeight || 620, 620);
  svg.setAttribute('viewBox', `0 0 ${W} ${H}`);
  const byId = Object.fromEntries(DATA.assets.map(a=>[a.id,a]));

  const links = DATA.links.map(l=>{
    const a=byId[l.src], b=byId[l.dst];
    if(!a||!b) return '';
    const hot = [a,b].some(x => x.status==='DOWN' || x.status==='UNREACH');
    const x1=a.x+85, y1=a.y+34, x2=b.x+85, y2=b.y+34;
    const mx=(x1+x2)/2, my=(y1+y2)/2 - 20;
    return `<path class="link ${hot?'hot':''}" d="M${x1},${y1} Q${mx},${my} ${x2},${y2}"/>`;
  }).join('');

  const nodes = DATA.assets.map(a=>{
    const st = a.status || 'UNKNOWN';
    const ip = a.ip || 'no ip';
    return `<g class="node ${st} ${esc(a.kind)}" data-id="${esc(a.id)}" transform="translate(${a.x},${a.y})">
      <rect class="card" width="170" height="68" rx="14"/>
      <rect class="kind" x="12" y="12" width="44" height="18" rx="6"/>
      <text x="34" y="25" text-anchor="middle" fill="#c9d7e8" font-size="9" font-family="IBM Plex Sans,sans-serif">${esc(a.kind)}</text>
      <circle class="dot ${st}" cx="150" cy="21" r="5"/>
      <text class="title" x="12" y="48">${esc(a.name)}</text>
      <text class="meta" x="12" y="62">${esc(ip)}</text>
    </g>`;
  }).join('');

  svg.innerHTML = links + nodes;

  svg.querySelectorAll('.node').forEach(g=>{
    g.addEventListener('pointerdown', e=>{
      const a = DATA.assets.find(x=>x.id===g.dataset.id);
      drag = {id:g.dataset.id, ox:e.clientX, oy:e.clientY, bx:a.x, by:a.y};
      g.setPointerCapture(e.pointerId);
    });
    g.addEventListener('pointermove', e=>{
      if(!drag || drag.id!==g.dataset.id) return;
      const a = DATA.assets.find(x=>x.id===drag.id);
      a.x = Math.max(8, drag.bx + (e.clientX - drag.ox));
      a.y = Math.max(8, drag.by + (e.clientY - drag.oy));
      render();
    });
    g.addEventListener('pointerup', async ()=>{
      if(!drag || drag.id!==g.dataset.id) return;
      const a = DATA.assets.find(x=>x.id===drag.id);
      await fetch(`/api/assets/${a.id}/position`, {
        method:'PATCH', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({x:a.x,y:a.y})
      });
      drag=null;
    });
  });

  const st = DATA.stats || {};
  document.getElementById('stats').innerHTML = `
    <div class="stat up"><i></i><span>${st.up||0} up</span></div>
    <div class="stat down"><i></i><span>${st.down||0} down</span></div>
    <div class="stat unk"><i></i><span>${st.unknown||0} ?</span></div>`;

  const sel = document.getElementById('asset_id');
  const cur = sel.value;
  sel.innerHTML = `<option value="">— без привязки —</option>` +
    DATA.assets.map(a=>`<option value="${esc(a.id)}">${esc(a.name)}</option>`).join('');
  if (cur) sel.value = cur;

  document.getElementById('panel-changes').innerHTML = DATA.changes.length
    ? DATA.changes.map(c=>`
      <div class="change">
        <div class="t">${esc(c.title)}</div>
        <div class="d">${esc(c.detail||'')}</div>
        <div class="m"><span class="pill">${esc(c.asset_id||'—')}</span><span>${esc(c.author)}</span><span>${esc(c.created_at)}</span></div>
      </div>`).join('')
    : `<div class="change"><div class="d">Пока пусто — запиши первое изменение ниже</div></div>`;

  document.getElementById('panel-assets').innerHTML = DATA.assets.map(a=>`
    <div class="asset-row" onclick="focusAsset('${esc(a.id)}')">
      <div class="s ${esc(a.status)}"></div>
      <div>
        <div class="n">${esc(a.name)}</div>
        <div class="i">${esc(a.status)} · ${esc(a.ip||'no ip')} · ${esc(a.notes||'')}</div>
      </div>
    </div>`).join('');
}

function focusAsset(id){
  const a = DATA.assets.find(x=>x.id===id);
  if(!a) return;
  document.getElementById('asset_id').value = id;
  showTab('changes');
}

async function submitChange(e){
  e.preventDefault();
  const body = {
    asset_id: document.getElementById('asset_id').value || null,
    title: document.getElementById('title').value.trim(),
    detail: document.getElementById('detail').value.trim(),
    author: document.getElementById('author').value.trim() || 'it'
  };
  await fetch('/api/changes', {method:'POST', headers:{'Content-Type':'application/json'}, body:JSON.stringify(body)});
  document.getElementById('title').value='';
  document.getElementById('detail').value='';
  await loadMap();
  showTab('changes');
  return false;
}

loadMap();
setInterval(loadMap, 20000);
</script>
</body>
</html>
