def fetch_checkmk_states() -> dict[str, dict[str, Any]]:
    """host_name -> {status, plugin_output, state_code} from PING / host services."""
    out: dict[str, dict[str, Any]] = {}
    try:
        with httpx.Client(timeout=6.0, follow_redirects=True) as client:
            auth = (CMK_USER, CMK_PASS)
            headers = {"Accept": "application/json"}
            # Prefer service states (PING) — host collection often omits state in Raw
            rs = client.get(
                f"{CMK_URL}/check_mk/api/1.0/domain-types/service/collections/all",
                auth=auth,
                headers=headers,
            )
            if rs.status_code == 200:
                for s in rs.json().get("value", []):
                    ext = s.get("extensions", {}) or {}
                    host = ext.get("host_name") or ""
                    desc = (ext.get("description") or "").upper()
                    st = ext.get("state")
                    if st is None:
                        st = ext.get("hard_state")
                    # Keep PING as primary; fallback any service
                    if host and (desc == "PING" or host not in out):
                        status = STATE_MAP.get(st, "UP" if st is None else str(st))
                        out[host] = {
                            "status": status,
                            "output": ext.get("plugin_output") or desc,
                            "state_code": st,
                        }
            # Ensure all configured hosts appear at least as monitored
            rh = client.get(
                f"{CMK_URL}/check_mk/api/1.0/domain-types/host/collections/all",
                auth=auth,
                headers=headers,
            )
            if rh.status_code == 200:
                for h in rh.json().get("value", []):
                    ext = h.get("extensions", {}) or {}
                    name = ext.get("name") or h.get("id") or ""
                    if name and name not in out:
                        out[name] = {"status": "UP", "output": "monitored", "state_code": None}
    except Exception:
        pass
    return out

