def ts_age(ts: Optional[int]) -> Optional[str]:
    if not ts:
        return None
    try:
        age = int(time.time()) - int(ts)
    except (TypeError, ValueError):
        return None
    if age < 60:
        return f"{age}s"
    if age < 3600:
        return f"{age // 60}m"
    return f"{age // 3600}h"


