def init_db() -> None:
    with db() as conn:
        conn.executescript(
            """
            CREATE TABLE IF NOT EXISTS assets (
                id TEXT PRIMARY KEY,
                name TEXT NOT NULL,
                kind TEXT NOT NULL,
                ip TEXT,
                checkmk_host TEXT,
                x REAL NOT NULL DEFAULT 100,
                y REAL NOT NULL DEFAULT 100,
                notes TEXT DEFAULT '',
                meta TEXT DEFAULT '{}'
            );
            CREATE TABLE IF NOT EXISTS links (
                src TEXT NOT NULL,
                dst TEXT NOT NULL,
                PRIMARY KEY (src, dst)
            );
            CREATE TABLE IF NOT EXISTS changes (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                asset_id TEXT,
                title TEXT NOT NULL,
                detail TEXT DEFAULT '',
                author TEXT DEFAULT 'it',
                created_at TEXT NOT NULL
            );
            """
        )
        n = conn.execute("SELECT COUNT(*) AS c FROM assets").fetchone()["c"]
        if n == 0:
            for a in SEED_ASSETS:
                meta = json.dumps({"probes": DEFAULT_PROBES.get(a[0], {})}, ensure_ascii=False)
                conn.execute(
                    "INSERT INTO assets(id,name,kind,ip,checkmk_host,x,y,notes,meta) VALUES (?,?,?,?,?,?,?,?,?)",
                    (*a, meta),
                )
            for s, d in SEED_LINKS:
                conn.execute("INSERT OR IGNORE INTO links(src,dst) VALUES (?,?)", (s, d))
            conn.execute(
                "INSERT INTO changes(asset_id,title,detail,author,created_at) VALUES (?,?,?,?,?)",
                (
                    "checkmk",
                    "Развёрнут Checkmk + Port Infra",
                    "CT 126 @ 192.168.2.172. Прод-сервисы не затрагивались.",
                    "auto",
                    utcnow(),
                ),
            )
        else:
            for aid, cmk in [
                ("gw", "gateway"),
                ("prox", "proxmox"),
                ("mail", "mail"),
                ("samba", "samba"),
                ("proxy", "proxy"),
                ("miko", "mikopbx"),
                ("checkmk", "checkmk"),
                ("crm", "h122"),
                ("zabbix", "h10"),
                ("grafana", "h114"),
            ]:
                conn.execute(
                    "UPDATE assets SET checkmk_host=? WHERE id=?",
                    (cmk, aid),
                )
            for aid, probes in DEFAULT_PROBES.items():
                row = conn.execute("SELECT meta FROM assets WHERE id=?", (aid,)).fetchone()
                if not row:
                    continue
                try:
                    meta = json.loads(row["meta"] or "{}")
                except json.JSONDecodeError:
                    meta = {}
                if "probes" not in meta:
                    meta["probes"] = probes
                    conn.execute(
                        "UPDATE assets SET meta=? WHERE id=?",
                        (json.dumps(meta, ensure_ascii=False), aid),
                    )


init_db()


