def row_dict(r: sqlite3.Row) -> dict[str, Any]:
    return dict(r)


def code_to_status(code: Any) -> str:
    if code is None or code == "":
        return "UNKNOWN"
    return STATE_MAP.get(code, STATE_MAP.get(str(code), "UNKNOWN"))


def worse(a: str, b: str) -> str:
    return a if STATE_RANK.get(a, 0) >= STATE_RANK.get(b, 0) else b


def livestatus_query(query: str, sep: str = ";") -> list[list[str]]:
    """Query Checkmk Livestatus unix socket. Returns rows as lists of fields."""
    if not os.path.exists(LIVESTATUS_SOCKET):
        return []
    sock = socket.socket(socket.AF_UNIX, socket.SOCK_STREAM)
    sock.settimeout(4.0)
    try:
        sock.connect(LIVESTATUS_SOCKET)
        sock.sendall((query.strip() + "\n\n").encode())
        buf = b""
        while True:
            chunk = sock.recv(65536)
            if not chunk:
                break
            buf += chunk
        text = buf.decode("utf-8", errors="replace").strip()
        if not text:
            return []
        return [line.split(sep) for line in text.splitlines() if line.strip()]
    except OSError:
        return []
    finally:
        sock.close()


def fetch_livestatus_hosts() -> dict[str, dict[str, Any]]:
    rows = livestatus_query(
        "GET hosts\nColumns: name address state hard_state plugin_output last_check latency\n"
    )
    out: dict[str, dict[str, Any]] = {}
    for row in rows:
        if len(row) < 6:
            continue
        name, address, state, hard, output, last_check = row[:6]
        latency = row[6] if len(row) > 6 else ""
        st = code_to_status(hard if hard not in ("", None) else state)
        out[name] = {
            "status": st,
            "output": output,
            "state_code": int(hard or state or 0) if str(hard or state).isdigit() else None,
            "last_check": int(last_check) if str(last_check).isdigit() else None,
            "last_check_age": ts_age(int(last_check) if str(last_check).isdigit() else None),
            "latency_ms": float(latency) * 1000 if latency else None,
            "address": address,
            "source": "livestatus_host",
        }
    return out


def fetch_livestatus_ping_services() -> dict[str, dict[str, Any]]:
    rows = livestatus_query(
        "GET services\nColumns: host_name description state hard_state plugin_output last_check latency\n"
        "Filter: description = PING\n"
    )
    out: dict[str, dict[str, Any]] = {}
    for row in rows:
        if len(row) < 6:
            continue
        host, desc, state, hard, output, last_check = row[:6]
        latency = row[6] if len(row) > 6 else ""
        st = code_to_status(hard if hard not in ("", None) else state)
        out[host] = {
            "status": st,
            "output": output,
            "state_code": int(hard or state or 0) if str(hard or state).isdigit() else None,
            "last_check": int(last_check) if str(last_check).isdigit() else None,
            "last_check_age": ts_age(int(last_check) if str(last_check).isdigit() else None),
            "latency_ms": float(latency) * 1000 if latency else None,
            "service": desc,
            "source": "livestatus_ping",
        }
    return out


def fetch_livestatus_problems() -> list[dict[str, Any]]:
    rows = livestatus_query(
        "GET services\nColumns: host_name description state hard_state plugin_output last_check\n"
        "Filter: state > 0\n"
    )
    problems = []
    for row in rows:
        if len(row) < 5:
            continue
        host, desc, state, hard, output, *rest = row
        last_check = rest[0] if rest else ""
        st = code_to_status(hard if hard not in ("", None) else state)
        problems.append(
            {
                "host": host,
                "service": desc,
                "status": st,
                "output": output,
                "last_check_age": ts_age(int(last_check) if str(last_check).isdigit() else None),
            }
        )
    rows_h = livestatus_query(
        "GET hosts\nColumns: name state hard_state plugin_output last_check\nFilter: state > 0\n"
    )
    for row in rows_h:
        if len(row) < 4:
            continue
        name, state, hard, output, *rest = row
        last_check = rest[0] if rest else ""
        st = code_to_status(hard if hard not in ("", None) else state)
        problems.append(
            {
                "host": name,
                "service": "HOST",
                "status": st,
                "output": output,
                "last_check_age": ts_age(int(last_check) if str(last_check).isdigit() else None),
            }
        )
    return problems


def probe_tcp(ip: str, port: int, timeout: float = 2.0) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with socket.create_connection((ip, port), timeout=timeout):
            ms = round((time.monotonic() - t0) * 1000, 1)
            return {"status": "UP", "output": f"TCP {port} open ({ms}ms)", "latency_ms": ms}
    except OSError as e:
        return {"status": "DOWN", "output": f"TCP {port} closed: {e}", "latency_ms": None}


def probe_http(url: str, timeout: float = 3.0) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with httpx.Client(timeout=timeout, follow_redirects=True, verify=False) as client:
            r = client.get(url)
            ms = round((time.monotonic() - t0) * 1000, 1)
            ok = r.status_code < 500
            return {
                "status": "UP" if ok else "DOWN",
                "output": f"HTTP {r.status_code} ({ms}ms) {url}",
                "latency_ms": ms,
            }
    except Exception as e:
        return {"status": "DOWN", "output": f"HTTP fail {url}: {e}", "latency_ms": None}


def run_asset_probes(asset: dict[str, Any]) -> list[dict[str, Any]]:
    try:
        meta = json.loads(asset.get("meta") or "{}")
    except json.JSONDecodeError:
        meta = {}
    probes = meta.get("probes") or DEFAULT_PROBES.get(asset["id"], {})
    ip = asset.get("ip")
    results = []
    for port in probes.get("tcp", []):
        target = "127.0.0.1" if asset["id"] == "checkmk" else ip
        if not target:
            continue
        r = probe_tcp(target, int(port))
        r["check"] = f"tcp:{port}"
        results.append(r)
    for url in probes.get("http", []):
        r = probe_http(url)
        r["check"] = f"http:{urlparse(url).netloc or url}"
        results.append(r)
    return results


def fetch_checkmk_monitoring() -> dict[str, Any]:
    """Full Checkmk snapshot via Livestatus (real states, not REST stubs)."""
    hosts = fetch_livestatus_hosts()
    ping = fetch_livestatus_ping_services()
    # merge: host state wins; ping fills gaps
    merged = dict(ping)
    for name, info in hosts.items():
        if name in merged:
            merged[name]["status"] = worse(merged[name]["status"], info["status"])
            if info["status"] != "UP":
                merged[name]["output"] = info["output"] or merged[name]["output"]
            merged[name]["source"] = "livestatus_host+ping"
        else:
            merged[name] = info
    problems = fetch_livestatus_problems()
    return {
        "hosts": merged,
        "problems": problems,
        "livestatus_ok": bool(merged),
        "fetched_at": utcnow(),
    }


def apply_monitoring_to_assets(assets: list[dict[str, Any]], cmk: dict[str, Any]) -> dict[str, int]:
    hosts = cmk.get("hosts", {})
    up = down = unk = 0
    for a in assets:
        key = a.get("checkmk_host") or ""
        ip = a.get("ip") or ""
        info = hosts.get(key) or hosts.get(ip) or {}
        status = info.get("status") or "UNKNOWN"
        output = info.get("output") or ""
        source = info.get("source") or "none"
        latency = info.get("latency_ms")
        last_age = info.get("last_check_age")
        checks = []

        if info:
            checks.append(
                {
                    "name": "checkmk",
                    "status": status,
                    "output": output,
                    "latency_ms": latency,
                }
            )

        # доп. пробы — усиливают картину (хуже статус побеждает)
        for pr in run_asset_probes(a):
            checks.append({"name": pr["check"], "status": pr["status"], "output": pr["output"], "latency_ms": pr.get("latency_ms")})
            status = worse(status, pr["status"])
            if pr["status"] != "UP" and not output:
                output = pr["output"]

        a["status"] = status
        a["cmk_output"] = output
        a["checks"] = checks
        a["monitor_source"] = source if info else ("probes" if checks else "none")
        a["last_check_age"] = last_age
        a["latency_ms"] = latency

        if status == "UP":
            up += 1
        elif status in ("DOWN", "UNREACH"):
            down += 1
        else:
            unk += 1
    return {"up": up, "down": down, "unknown": unk, "total": len(assets)}


def build_map_payload() -> dict[str, Any]:
    with db() as conn:
        assets = [row_dict(r) for r in conn.execute("SELECT * FROM assets ORDER BY name")]
        links = [row_dict(r) for r in conn.execute("SELECT * FROM links")]
        changes = [
            row_dict(r)
            for r in conn.execute("SELECT * FROM changes ORDER BY id DESC LIMIT 40")
        ]
    cmk = fetch_checkmk_monitoring()
    stats = apply_monitoring_to_assets(assets, cmk)
    return {
        "assets": assets,
        "links": links,
        "changes": changes,
        "stats": stats,
        "problems": cmk.get("problems", []),
        "monitoring": {
            "source": "checkmk_livestatus",
            "livestatus_ok": cmk.get("livestatus_ok"),
            "fetched_at": cmk.get("fetched_at"),
            "host_count": len(cmk.get("hosts", {})),
        },
    }


