        "livestatus_socket": LIVESTATUS_SOCKET,
        "hosts_monitored": len(cmk.get("hosts", {})),
        "problems": len(cmk.get("problems", [])),
    }


@app.get("/api/map")
def get_map():
    return build_map_payload()


@app.get("/api/stream")
async def stream():
    async def gen():
        while True:
            payload = build_map_payload()
            yield f"data: {json.dumps(payload, ensure_ascii=False)}\n\n"
            await asyncio.sleep(STREAM_INTERVAL)

    return StreamingResponse(
        gen(),
        media_type="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )


@app.post("/api/assets")
def create_asset(body: AssetIn):
    aid = body.id or body.name.lower().replace(" ", "-")[:40]
    meta = json.dumps({"probes": DEFAULT_PROBES.get(aid, {})}, ensure_ascii=False)
    with db() as conn:
        try:
            conn.execute(
                "INSERT INTO assets(id,name,kind,ip,checkmk_host,x,y,notes,meta) VALUES (?,?,?,?,?,?,?,?,?)",
                (aid, body.name, body.kind, body.ip, body.checkmk_host, body.x, body.y, body.notes, meta),
            )
        except sqlite3.IntegrityError:
            raise HTTPException(400, "asset id exists")
    return {"id": aid}


@app.patch("/api/assets/{aid}/position")
def move_asset(aid: str, body: AssetPos):
    with db() as conn:
        cur = conn.execute("UPDATE assets SET x=?, y=? WHERE id=?", (body.x, body.y, aid))
        if cur.rowcount == 0:
            raise HTTPException(404)
    return {"ok": True}


@app.post("/api/changes")
def add_change(body: ChangeIn):
    with db() as conn:
        cur = conn.execute(
            "INSERT INTO changes(asset_id,title,detail,author,created_at) VALUES (?,?,?,?,?)",
            (body.asset_id, body.title, body.detail, body.author, utcnow()),
        )
        cid = cur.lastrowid
    return {"id": cid}


