    <div class="hint">Live SSE ~5s · статусы из Checkmk Livestatus + TCP/HTTP пробы</div>
  </div>
  <aside>
    <div class="tabs">
      <button class="active" data-tab="problems" onclick="showTab('problems')">Проблемы</button>
      <button data-tab="assets" onclick="showTab('assets')">Узлы</button>
      <button data-tab="changes" onclick="showTab('changes')">Журнал</button>
    </div>
    <div class="panel" id="panel-problems"></div>
    <div class="panel" id="panel-assets" style="display:none"></div>
    <div class="panel" id="panel-changes" style="display:none"></div>
    <div class="composer">
      <form id="f" onsubmit="return submitChange(event)">
        <div><label>Узел</label><select id="asset_id"></select></div>
        <div><label>Что изменилось</label><input id="title" placeholder="Напр. Сменилась база трубки 213" required/></div>
        <div><label>Детали</label><textarea id="detail" rows="2" placeholder="Было → стало"></textarea></div>
        <div class="row"><div><label>Автор</label><input id="author" value="it"/></div>
        <div style="display:flex;align-items:end"><button class="btn" type="submit">Записать</button></div></div>
      </form>
    </div>
  </aside>
</div>
<script>
let DATA={assets:[],links:[],changes:[],stats:{},problems:[],monitoring:{}};
let drag=null, es=null;

function showTab(name){
  document.querySelectorAll('.tabs button').forEach(b=>b.classList.toggle('active',b.dataset.tab===name));
  ['problems','assets','changes'].forEach(t=>{
    document.getElementById('panel-'+t).style.display = t===name?'block':'none';
  });
}
function esc(s){return String(s??'').replace(/[&<>"']/g,m=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[m]));}

function render(){
  if(drag) return;
  const svg=document.getElementById('map');
  const W=Math.max(svg.clientWidth||900,900), H=Math.max(svg.clientHeight||620,620);
  svg.setAttribute('viewBox',`0 0 ${W} ${H}`);
  const byId=Object.fromEntries(DATA.assets.map(a=>[a.id,a]));
  const links=DATA.links.map(l=>{
    const a=byId[l.src], b=byId[l.dst]; if(!a||!b) return '';
    const hot=[a,b].some(x=>x.status==='DOWN'||x.status==='UNREACH');
    const x1=a.x+85,y1=a.y+38,x2=b.x+85,y2=b.y+38,mx=(x1+x2)/2,my=(y1+y2)/2-20;
    return `<path class="link ${hot?'hot':''}" d="M${x1},${y1} Q${mx},${my} ${x2},${y2}"/>`;
  }).join('');
  const nodes=DATA.assets.map(a=>{
    const st=a.status||'UNKNOWN';
    const age=a.last_check_age?` · ${a.last_check_age}`:'';
    const lat=a.latency_ms!=null?` · ${Math.round(a.latency_ms)}ms`:'';
    return `<g class="node ${st} ${esc(a.kind)}" data-id="${esc(a.id)}" transform="translate(${a.x},${a.y})">
      <rect class="card" width="170" height="74" rx="14"/>
      <circle class="dot ${st}" cx="150" cy="18" r="5"/>
      <text class="title" x="12" y="24">${esc(a.name)}</text>
      <text class="meta" x="12" y="40">${esc(a.ip||'no ip')} · ${esc(st)}</text>
      <text class="submeta" x="12" y="54">${esc((a.cmk_output||'').slice(0,42))}${(a.cmk_output||'').length>42?'…':''}</text>
      <text class="submeta" x="12" y="66">${esc(a.kind)}${esc(age)}${esc(lat)}</text>
    </g>`;
  }).join('');
  svg.innerHTML=links+nodes;
  svg.querySelectorAll('.node').forEach(g=>{
    g.addEventListener('pointerdown',e=>{
      const a=DATA.assets.find(x=>x.id===g.dataset.id);
      drag={id:g.dataset.id,ox:e.clientX,oy:e.clientY,bx:a.x,by:a.y};
      g.setPointerCapture(e.pointerId);
    });
    g.addEventListener('pointermove',e=>{
      if(!drag||drag.id!==g.dataset.id) return;
      const a=DATA.assets.find(x=>x.id===drag.id);
      a.x=Math.max(8,drag.bx+(e.clientX-drag.ox));
      a.y=Math.max(8,drag.by+(e.clientY-drag.oy));
      render();
    });
    g.addEventListener('pointerup',async()=>{
      if(!drag||drag.id!==g.dataset.id) return;
      const a=DATA.assets.find(x=>x.id===drag.id);
      await fetch(`/api/assets/${a.id}/position`,{method:'PATCH',headers:{'Content-Type':'application/json'},body:JSON.stringify({x:a.x,y:a.y})});
      drag=null;
    });
  });
  const st=DATA.stats||{};
  document.getElementById('stats').innerHTML=`
    <div class="stat up"><i></i><span>${st.up||0} up</span></div>
    <div class="stat down"><i></i><span>${st.down||0} down</span></div>
    <div class="stat unk"><i></i><span>${st.unknown||0} ?</span></div>`;
  const sel=document.getElementById('asset_id'), cur=sel.value;
  sel.innerHTML=`<option value="">— без привязки —</option>`+DATA.assets.map(a=>`<option value="${esc(a.id)}">${esc(a.name)}</option>`).join('');
  if(cur) sel.value=cur;

  const probs=DATA.problems||[];
  document.getElementById('panel-problems').innerHTML = probs.length ? probs.map(p=>`
    <div class="problem">
      <div class="t">${esc(p.host)} / ${esc(p.service)} <span class="pill bad">${esc(p.status)}</span></div>
      <div class="d">${esc(p.output||'')}</div>
      <div class="m"><span>${esc(p.last_check_age||'?')}</span></div>
    </div>`).join('') : `<div class="problem"><div class="d">Проблем нет — всё зелёное</div></div>`;

  document.getElementById('panel-assets').innerHTML=DATA.assets.map(a=>{
    const checks=(a.checks||[]).map(c=>`${c.name}:${c.status}`).join(' · ');
    return `<div class="asset-row" onclick="focusAsset('${esc(a.id)}')">
      <div class="s ${esc(a.status)}"></div>
      <div><div class="n">${esc(a.name)}</div>
      <div class="i">${esc(a.status)} · ${esc(a.ip||'')} · ${esc(a.last_check_age||'?')} ago<br>${esc(a.cmk_output||'')}${checks?'<br>'+esc(checks):''}</div></div>
    </div>`;
  }).join('');

  document.getElementById('panel-changes').innerHTML=DATA.changes.length?DATA.changes.map(c=>`
    <div class="change"><div class="t">${esc(c.title)}</div><div class="d">${esc(c.detail||'')}</div>
    <div class="m"><span class="pill">${esc(c.asset_id||'—')}</span><span>${esc(c.author)}</span><span>${esc(c.created_at)}</span></div></div>`).join('')
    : `<div class="change"><div class="d">Пока пусто</div></div>`;

  const mon=DATA.monitoring||{};
  document.getElementById('live').innerHTML=`<i></i><span>${mon.fetched_at||'—'} · ${mon.host_count||0} hosts</span>`;
  document.getElementById('live').classList.toggle('ok', !!mon.livestatus_ok);
}

async function loadMap(){
  const r=await fetch('/api/map'); DATA=await r.json(); render();
}
function focusAsset(id){ document.getElementById('asset_id').value=id; showTab('changes'); }
async function submitChange(e){
  e.preventDefault();
  await fetch('/api/changes',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({
    asset_id:document.getElementById('asset_id').value||null,
    title:document.getElementById('title').value.trim(),
    detail:document.getElementById('detail').value.trim(),
    author:document.getElementById('author').value.trim()||'it'
  })});
  document.getElementById('title').value=''; document.getElementById('detail').value='';
  await loadMap(); showTab('changes'); return false;
}
function connectSSE(){
  if(es) es.close();
  es=new EventSource('/api/stream');
  es.onmessage=(ev)=>{ try{ DATA=JSON.parse(ev.data); render(); }catch(e){} };
  es.onerror=()=>{ document.getElementById('live').classList.remove('ok'); setTimeout(connectSSE,3000); };
}
loadMap(); connectSSE();
</script>
</body>
</html>
