        info = hosts.get(key) or hosts.get(ip) or {}
        cmk_status = info.get("status") or "UNKNOWN"
        output = info.get("output") or ""
        source = info.get("source") or "none"
        latency = info.get("latency_ms")
        last_age = info.get("last_check_age")
        checks = []

        if info:
            checks.append(
                {
                    "name": "checkmk",
                    "status": cmk_status,
                    "output": output,
                    "latency_ms": latency,
                }
            )

        probe_results = run_asset_probes(a)
        probe_fail = [pr for pr in probe_results if pr["status"] != "UP"]
        for pr in probe_results:
            checks.append(
                {
                    "name": pr["check"],
                    "status": pr["status"],
                    "output": pr["output"],
                    "latency_ms": pr.get("latency_ms"),
                }
            )

        # Карта: цвет узла по Checkmk (реальный PING/host). Пробы — WARN, не маскируют UP.
        if cmk_status in ("DOWN", "UNREACH"):
            status = cmk_status
        elif probe_fail and cmk_status == "UP":
            status = "WARN"
            if not output:
                output = probe_fail[0]["output"]
        elif not info and probe_results:
            status = worse(*(pr["status"] for pr in probe_results))
            if not output and probe_fail:
                output = probe_fail[0]["output"]
        else:
            status = cmk_status

        a["status"] = status
        a["cmk_status"] = cmk_status
        a["cmk_output"] = output
        a["checks"] = checks
        a["monitor_source"] = source if info else ("probes" if checks else "none")
        a["last_check_age"] = last_age
        a["latency_ms"] = latency
        a["probe_alerts"] = len(probe_fail)

        if status == "UP":
            up += 1
        elif status == "WARN":
            warn += 1
        elif status in ("DOWN", "UNREACH"):
            down += 1
        else:
            unk += 1
    return {"up": up, "down": down, "warn": warn, "unknown": unk, "total": len(assets)}

