def collect_probe_problems(assets: list[dict[str, Any]]) -> list[dict[str, Any]]:
    out = []
    for a in assets:
        for c in a.get("checks", []):
            if c.get("name") != "checkmk" and c.get("status") not in ("UP", None):
                out.append(
                    {
                        "host": a.get("name") or a.get("id"),
                        "service": c.get("name", "probe"),
                        "status": c.get("status"),
                        "output": c.get("output", ""),
                        "last_check_age": a.get("last_check_age"),
                    }
                )
    return out

