def asset_meta(aid: str) -> str:
    return json.dumps({"probes": DEFAULT_PROBES.get(aid, {})}, ensure_ascii=False)


def sync_catalog(conn: sqlite3.Connection) -> None:
    """Добавляет новые узлы из catalog.py, обновляет метаданные, не трогает x/y существующих."""
    conn.execute(
        "CREATE TABLE IF NOT EXISTS meta_kv (k TEXT PRIMARY KEY, v TEXT NOT NULL)"
    )
    for a in SEED_ASSETS:
        aid, name, kind, ip, cmk, x, y, notes = a
        meta = asset_meta(aid)
        row = conn.execute("SELECT id FROM assets WHERE id=?", (aid,)).fetchone()
        if row:
            conn.execute(
                "UPDATE assets SET name=?, kind=?, ip=?, checkmk_host=?, notes=?, meta=? WHERE id=?",
                (name, kind, ip, cmk, notes, meta, aid),
            )
        else:
            conn.execute(
                "INSERT INTO assets(id,name,kind,ip,checkmk_host,x,y,notes,meta) VALUES (?,?,?,?,?,?,?,?,?)",
                (aid, name, kind, ip, cmk, x, y, notes, meta),
            )
    for src, dst in SEED_LINKS:
        conn.execute("INSERT OR IGNORE INTO links(src,dst) VALUES (?,?)", (src, dst))
    conn.execute(
        "INSERT OR REPLACE INTO meta_kv(k,v) VALUES (?,?)",
        ("catalog_version", str(CATALOG_VERSION)),
    )


