STREAM_INTERVAL = float(os.environ.get("PORT_INFRA_STREAM_SEC", "8"))
PROBE_CACHE_TTL = float(os.environ.get("PORT_INFRA_PROBE_TTL", "12"))
_PROBE_CACHE: dict[str, tuple[float, list[dict[str, Any]]]] = {}

def probe_tcp(ip: str, port: int, timeout: float = 1.2) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with socket.create_connection((ip, port), timeout=timeout):
            ms = round((time.monotonic() - t0) * 1000, 1)
            return {"status": "UP", "output": f"TCP {port} open ({ms}ms)", "latency_ms": ms}
    except OSError as e:
        return {"status": "DOWN", "output": f"TCP {port} closed: {e}", "latency_ms": None}


def probe_http(url: str, timeout: float = 2.0) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with httpx.Client(timeout=timeout, follow_redirects=True, verify=False) as client:
            r = client.get(url)
            ms = round((time.monotonic() - t0) * 1000, 1)
            ok = r.status_code < 500
            return {
                "status": "UP" if ok else "DOWN",
                "output": f"HTTP {r.status_code} ({ms}ms) {url}",
                "latency_ms": ms,
            }
    except Exception as e:
        return {"status": "DOWN", "output": f"HTTP fail {url}: {e}", "latency_ms": None}


def run_asset_probes(asset: dict[str, Any]) -> list[dict[str, Any]]:
    aid = asset["id"]
    cached = _PROBE_CACHE.get(aid)
    if cached and (time.monotonic() - cached[0]) < PROBE_CACHE_TTL:
        return cached[1]
    try:
        meta = json.loads(asset.get("meta") or "{}")
    except json.JSONDecodeError:
        meta = {}
    probes = meta.get("probes") or DEFAULT_PROBES.get(aid, {})
    if not probes:
        _PROBE_CACHE[aid] = (time.monotonic(), [])
        return []
    ip = asset.get("ip")
    results = []
    for port in probes.get("tcp", []):
        target = "127.0.0.1" if aid == "checkmk" else ip
        if not target:
            continue
        r = probe_tcp(target, int(port))
        r["check"] = f"tcp:{port}"
        results.append(r)
    for url in probes.get("http", []):
        r = probe_http(url)
        r["check"] = f"http:{urlparse(url).netloc or url}"
        results.append(r)
    _PROBE_CACHE[aid] = (time.monotonic(), results)
    return results

