def probe_icmp(ip: str, timeout: float = 1.5) -> dict[str, Any]:
    """ICMP via system ping (Linux). CIDR / non-IP skipped by caller."""
    import subprocess

    t0 = time.monotonic()
    try:
        r = subprocess.run(
            ["ping", "-c", "1", "-W", str(max(1, int(timeout))), ip],
            capture_output=True,
            text=True,
            timeout=timeout + 1.5,
        )
        ms = round((time.monotonic() - t0) * 1000, 1)
        if r.returncode == 0:
            # try parse time= from output
            for part in (r.stdout or "").replace("=", " ").split():
                if part.endswith("ms") and part[:-2].replace(".", "", 1).isdigit():
                    try:
                        ms = float(part[:-2])
                    except ValueError:
                        pass
                    break
            return {"status": "UP", "output": f"ICMP OK ({ms}ms)", "latency_ms": ms}
        return {"status": "DOWN", "output": f"ICMP fail: {ip}", "latency_ms": None}
    except Exception as e:
        return {"status": "DOWN", "output": f"ICMP error: {e}", "latency_ms": None}


def probe_tcp(ip: str, port: int, timeout: float = 1.2) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with socket.create_connection((ip, port), timeout=timeout):
            ms = round((time.monotonic() - t0) * 1000, 1)
            return {"status": "UP", "output": f"TCP {port} open ({ms}ms)", "latency_ms": ms}
    except OSError as e:
        return {"status": "DOWN", "output": f"TCP {port} closed: {e}", "latency_ms": None}


def probe_http(url: str, timeout: float = 2.0) -> dict[str, Any]:
    t0 = time.monotonic()
    try:
        with httpx.Client(timeout=timeout, follow_redirects=True, verify=False) as client:
            r = client.get(url)
            ms = round((time.monotonic() - t0) * 1000, 1)
            ok = r.status_code < 500
            return {
                "status": "UP" if ok else "DOWN",
                "output": f"HTTP {r.status_code} ({ms}ms) {url}",
                "latency_ms": ms,
            }
    except Exception as e:
        return {"status": "DOWN", "output": f"HTTP fail {url}: {e}", "latency_ms": None}


def is_plain_ip(ip: Optional[str]) -> bool:
    if not ip or "/" in ip:
        return False
    parts = ip.split(".")
    if len(parts) != 4:
        return False
    try:
        return all(0 <= int(p) <= 255 for p in parts)
    except ValueError:
        return False


def run_tcp_http_probes(asset: dict[str, Any]) -> list[dict[str, Any]]:
    cfg = get_settings()
    if not cfg["tcp_probes_enabled"]:
        return []
    aid = asset["id"]
    ttl = float(cfg["ping_interval_sec"])
    cached = _PROBE_CACHE.get(aid)
    if cached and (time.monotonic() - cached[0]) < ttl:
        return cached[1]
    try:
        meta = json.loads(asset.get("meta") or "{}")
    except json.JSONDecodeError:
        meta = {}
    probes = meta.get("probes") or DEFAULT_PROBES.get(aid, {})
    if not probes:
        _PROBE_CACHE[aid] = (time.monotonic(), [])
        return []
    ip = asset.get("ip")
    results = []
    for port in probes.get("tcp", []):
        target = "127.0.0.1" if aid == "checkmk" else ip
        if not target:
            continue
        r = probe_tcp(target, int(port))
        r["check"] = f"tcp:{port}"
        results.append(r)
    for url in probes.get("http", []):
        r = probe_http(url)
        r["check"] = f"http:{urlparse(url).netloc or url}"
        results.append(r)
    _PROBE_CACHE[aid] = (time.monotonic(), results)
    return results


def run_ping_round(force: bool = False) -> dict[str, Any]:
    """ICMP all plain IPs; stores in SQLite + memory. Default every ping_interval_sec."""
    global _LAST_PING_ROUND, _PING_IN_PROGRESS
    if _PING_IN_PROGRESS:
        return {"ok": False, "reason": "in_progress"}
    cfg = get_settings()
    if not cfg["icmp_enabled"] and not force:
        return {"ok": False, "reason": "icmp_disabled"}
    _PING_IN_PROGRESS = True
    try:
        with db() as conn:
            assets = [row_dict(r) for r in conn.execute("SELECT id,ip,name FROM assets")]
        checked = 0
        up = down = 0
        now = utcnow()
        for a in assets:
            ip = a.get("ip")
            if not is_plain_ip(ip):
                continue
            # skip loopback-style external that we can't/shouldn't hammer from CT? still ok
            r = probe_icmp(ip)
            r["check"] = "icmp"
            r["checked_at"] = now
            _PING_STATE[a["id"]] = r
            with db() as conn:
                conn.execute(
                    "INSERT OR REPLACE INTO ping_results(asset_id,status,output,latency_ms,checked_at) VALUES (?,?,?,?,?)",
                    (a["id"], r["status"], r["output"], r.get("latency_ms"), now),
                )
            checked += 1
            if r["status"] == "UP":
                up += 1
            else:
                down += 1
        _LAST_PING_ROUND = now
        # also refresh TCP/HTTP cache on same cadence
        _PROBE_CACHE.clear()
        return {"ok": True, "checked": checked, "up": up, "down": down, "at": now}
    finally:
        _PING_IN_PROGRESS = False


async def ping_worker() -> None:
    await asyncio.sleep(2)
    while True:
        try:
            await asyncio.to_thread(run_ping_round)
        except Exception:
            pass
        cfg = get_settings()
        await asyncio.sleep(max(60, int(cfg["ping_interval_sec"])))


@app.on_event("startup")
async def _startup() -> None:
    asyncio.create_task(ping_worker())

