def apply_monitoring_to_assets(assets: list[dict[str, Any]], cmk: dict[str, Any]) -> dict[str, int]:
    hosts = cmk.get("hosts", {})
    hosts_by_ip = cmk.get("hosts_by_ip", {})
    up = down = warn = unk = 0
    for a in assets:
        key = a.get("checkmk_host") or ""
        ip = a.get("ip") or ""
        info = hosts.get(key) or hosts_by_ip.get(ip) or {}
        cmk_status = info.get("status") or "UNKNOWN"
        output = info.get("output") or ""
        source = info.get("source") or "none"
        latency = info.get("latency_ms")
        last_age = info.get("last_check_age")
        checks = []

        if info:
            checks.append(
                {
                    "name": "checkmk",
                    "status": cmk_status,
                    "output": output,
                    "latency_ms": latency,
                }
            )

        icmp = _PING_STATE.get(a["id"])
        if icmp:
            checks.append(
                {
                    "name": "icmp",
                    "status": icmp["status"],
                    "output": icmp.get("output", ""),
                    "latency_ms": icmp.get("latency_ms"),
                }
            )
            if not last_age and icmp.get("checked_at"):
                # approximate age from string timestamp not parsed — show checked_at later
                pass
            if latency is None and icmp.get("latency_ms") is not None:
                latency = icmp["latency_ms"]
            if not output:
                output = icmp.get("output") or ""

        probe_results = run_tcp_http_probes(a)
        probe_fail = [pr for pr in probe_results if pr["status"] != "UP"]
        for pr in probe_results:
            checks.append(
                {
                    "name": pr["check"],
                    "status": pr["status"],
                    "output": pr["output"],
                    "latency_ms": pr.get("latency_ms"),
                }
            )

        icmp_st = icmp["status"] if icmp else None
        # Priority: Checkmk DOWN > ICMP DOWN > Checkmk/ICMP UP > TCP WARN > UNKNOWN
        if cmk_status in ("DOWN", "UNREACH"):
            status = cmk_status
        elif icmp_st in ("DOWN", "UNREACH"):
            status = icmp_st
            source = "icmp" if source == "none" else source + "+icmp"
        elif cmk_status == "UP" or icmp_st == "UP":
            status = "UP"
            if probe_fail:
                status = "WARN"
                if not output:
                    output = probe_fail[0]["output"]
            if source == "none" and icmp_st == "UP":
                source = "icmp"
        elif probe_results:
            status = "UNKNOWN"
            for pr in probe_results:
                status = worse(status, pr["status"])
            source = "probes"
        else:
            status = "UNKNOWN" if not is_plain_ip(ip) else "UNKNOWN"

        a["status"] = status
        a["cmk_status"] = cmk_status
        a["cmk_output"] = output
        a["checks"] = checks
        a["monitor_source"] = source if info or icmp else ("probes" if checks else "none")
        a["last_check_age"] = last_age or (icmp.get("checked_at") if icmp else None)
        a["latency_ms"] = latency
        a["probe_alerts"] = len(probe_fail) + (1 if icmp_st == "DOWN" else 0)

        if status == "UP":
            up += 1
        elif status == "WARN":
            warn += 1
        elif status in ("DOWN", "UNREACH"):
            down += 1
        else:
            unk += 1
    return {"up": up, "down": down, "warn": warn, "unknown": unk, "total": len(assets)}


def build_analytics(assets: list[dict[str, Any]], stats: dict[str, int]) -> dict[str, Any]:
    by_kind: dict[str, dict[str, int]] = {}
    with_ip = sum(1 for a in assets if is_plain_ip(a.get("ip")))
    monitored = sum(1 for a in assets if a.get("status") != "UNKNOWN")
    for a in assets:
        k = a.get("kind") or "other"
        bucket = by_kind.setdefault(k, {"total": 0, "up": 0, "down": 0, "warn": 0, "unknown": 0})
        bucket["total"] += 1
        st = (a.get("status") or "UNKNOWN").lower()
        if st in bucket:
            bucket[st] += 1
        else:
            bucket["unknown"] += 1
    return {
        "coverage_pct": round(100 * monitored / max(1, len(assets)), 1),
        "with_ip": with_ip,
        "without_ip": len(assets) - with_ip,
        "monitored": monitored,
        "by_kind": by_kind,
        "stats": stats,
        "last_ping_round": _LAST_PING_ROUND,
        "ping_interval_sec": get_settings()["ping_interval_sec"],
        "analogs": [
            {"name": "Checkmk", "role": "host/service state", "url": "http://192.168.2.172/cmk/"},
            {"name": "Zabbix", "role": "метрики + алерты", "url": "http://192.168.2.10/"},
            {"name": "Grafana", "role": "дашборды", "url": "http://192.168.2.114/"},
            {"name": "Port Infra", "role": "карта + журнал + сводка", "url": "/"},
        ],
    }


