def run_ping_round(force: bool = False) -> dict[str, Any]:
    """ICMP all plain IPs; stores in SQLite + memory. Default every ping_interval_sec."""
    global _LAST_PING_ROUND, _PING_IN_PROGRESS, _LAST_PING_TS, _NEXT_PING_TS
    if _PING_IN_PROGRESS:
        return {"ok": False, "reason": "in_progress"}
    cfg = get_settings()
    if not cfg["icmp_enabled"] and not force:
        return {"ok": False, "reason": "icmp_disabled"}
    _PING_IN_PROGRESS = True
    try:
        with db() as conn:
            assets = [row_dict(r) for r in conn.execute("SELECT id,ip,name FROM assets")]
        checked = 0
        up = down = 0
        now = utcnow()
        for a in assets:
            ip = a.get("ip")
            if not is_plain_ip(ip):
                continue
            r = probe_icmp(ip)
            r["check"] = "icmp"
            r["checked_at"] = now
            _PING_STATE[a["id"]] = r
            with db() as conn:
                conn.execute(
                    "INSERT OR REPLACE INTO ping_results(asset_id,status,output,latency_ms,checked_at) VALUES (?,?,?,?,?)",
                    (a["id"], r["status"], r["output"], r.get("latency_ms"), now),
                )
            checked += 1
            if r["status"] == "UP":
                up += 1
            else:
                down += 1
        _LAST_PING_ROUND = now
        _LAST_PING_TS = time.time()
        _NEXT_PING_TS = _LAST_PING_TS + max(60, int(cfg["ping_interval_sec"]))
        _PROBE_CACHE.clear()
        with db() as conn:
            full = [row_dict(r) for r in conn.execute("SELECT * FROM assets")]
        for a in full:
            run_tcp_http_probes(a)
        return {"ok": True, "checked": checked, "up": up, "down": down, "at": now, "next_ping_ts": _NEXT_PING_TS}
    finally:
        _PING_IN_PROGRESS = False


async def ping_worker() -> None:
    await asyncio.sleep(2)
    while True:
        try:
            await asyncio.to_thread(run_ping_round)
        except Exception:
            pass
        cfg = get_settings()
        wait = max(60, int(cfg["ping_interval_sec"]))
        # sleep until next scheduled time (or full interval)
        global _NEXT_PING_TS
        if _NEXT_PING_TS <= 0:
            _NEXT_PING_TS = time.time() + wait
        delay = max(5.0, _NEXT_PING_TS - time.time())
        await asyncio.sleep(delay)


