@app.post("/api/login")
def api_login(body: LoginIn, response: Response):
    if body.username != AUTH_USER or body.password != AUTH_PASS:
        raise HTTPException(401, "Неверный логин или пароль")
    tok = make_session_token()
    _SESSIONS.add(tok)
    response.set_cookie(
        key="port_session",
        value=tok,
        httponly=True,
        samesite="lax",
        max_age=60 * 60 * 24 * 14,
        path="/",
    )
    return {"ok": True, "user": AUTH_USER}


@app.post("/api/logout")
def api_logout(request: Request, response: Response):
    tok = request.cookies.get("port_session")
    if tok:
        _SESSIONS.discard(tok)
    response.delete_cookie("port_session", path="/")
    return {"ok": True}


