function renderSummary(){
  const an=DATA.analytics||{}, st=an.stats||DATA.stats||{};
  const kinds=Object.entries(an.by_kind||{}).sort((a,b)=>b[1].total-a[1].total);
  const analogs=(an.analogs||[]).map(a=>`
    <div class="analog"><div><b>${esc(a.name)}</b><div style="color:var(--muted);font-size:11px">${esc(a.role)}</div></div>
    <a href="${esc(a.url)}" target="_blank" rel="noopener">открыть</a></div>`).join('');
  document.getElementById('panel-summary').innerHTML=`
    <div class="metric">
      <div class="box"><div class="v">${an.coverage_pct??0}%</div><div class="l">coverage</div></div>
      <div class="box"><div class="v">${st.up||0}/${an.with_ip||0}</div><div class="l">up / с IP</div></div>
      <div class="box"><div class="v">${st.down||0}</div><div class="l">down</div></div>
      <div class="box"><div class="v">${st.unknown||0}</div><div class="l">без статуса</div></div>
    </div>
    <div class="card"><div class="t">ICMP</div>
      <div class="d">Интервал ${an.ping_interval_sec||600}с. Последний раунд: ${esc(an.last_ping_round||'—')}.</div></div>
    <div class="card"><div class="t">По типу</div>
      <div class="d">${kinds.map(([k,v])=>`${k}: ${v.up}↑ ${v.down}↓ ${v.unknown}? / ${v.total}`).join('\\n')||'—'}</div></div>
    <div class="card"><div class="t">Стек</div>${analogs}</div>`;
}

